import{_ as e,o,c as t,d as a}from"./app.22d6dd61.js";const g=JSON.parse('{"title":"Public Key Cryptography","description":"","frontmatter":{},"headers":[{"level":2,"title":"Keys for Deploying a Network","slug":"keys-for-deploying-a-network"},{"level":3,"title":"1. Generate new key-pairs","slug":"_1-generate-new-key-pairs"},{"level":3,"title":"2. Update keys for each peer","slug":"_2-update-keys-for-each-peer"},{"level":3,"title":"3. Register a non-genesis account","slug":"_3-register-a-non-genesis-account"},{"level":2,"title":"Keys on the Client Side","slug":"keys-on-the-client-side"}],"relativePath":"guide/configure/keys.md","lastUpdated":1659428266000}'),r={name:"guide/configure/keys.md"},i=a(`<h1 id="public-key-cryptography" tabindex="-1">Public Key Cryptography <a class="header-anchor" href="#public-key-cryptography" aria-hidden="true">#</a></h1><p>It&#39;s OK to feel worried about public key cryptography. This is a complex topic that requires a lot of care and attention. To work with Iroha you <em>do</em> need to have a basic understanding of how it works, so we provided you with a brief primer.</p><p>Firstly, public and private keys come in pairs. For a given private key it&#39;s easy to figure out the corresponding public key, but the opposite is not true. The fact that it&#39;s practically impossible to figure out the private key for a given public key is why they&#39;re called <em>public</em> and <em>private</em>: <strong>the public one is safe to share without compromising the security of the entire exchange</strong>.</p><p>With a private key, you can encrypt information in such a way that only the people who have your public key can read it. You cannot encrypt anything with a public key.</p><p>When you encrypt data with a private key, you <em>sign</em> it. When something is <em>signed</em>, everyone can read it, and everyone with your public key can verify that the person who wrote that message used your private key.</p><h2 id="keys-for-deploying-a-network" tabindex="-1">Keys for Deploying a Network <a class="header-anchor" href="#keys-for-deploying-a-network" aria-hidden="true">#</a></h2><p>Keeping in mind what we said above about key cryptography, note that if you&#39;re deploying your own network, you should change the keys in all three configuration files (<a href="./peer-configuration.html"><code>/configs/peer/config.json</code></a>, <a href="./client-configuration.html"><code>configs/client_cli/config.json </code></a>, and <a href="./genesis.html"><code>configs/peer/genesis.json</code></a>).</p><h3 id="_1-generate-new-key-pairs" tabindex="-1">1. Generate new key-pairs <a class="header-anchor" href="#_1-generate-new-key-pairs" aria-hidden="true">#</a></h3><p>To get new key-pairs, use the <code>iroha_crypto_cli</code> program:</p><div class="language-bash"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#ADBAC7;">cargo build -p iroha_crypto_cli</span></span>
<span class="line"><span style="color:#ADBAC7;">./target/debug/iroha_crypto_cli</span></span>
<span class="line"></span></code></pre></div><p>This will print a fresh pair of keys.</p><h3 id="_2-update-keys-for-each-peer" tabindex="-1">2. Update keys for each peer <a class="header-anchor" href="#_2-update-keys-for-each-peer" aria-hidden="true">#</a></h3><p>If you want to set up your own network, you should change the keys for all your peers: in <code>peer/config.json</code> change <code>PUBLIC_KEY</code> and <code>PRIVATE_KEY</code> to the fresh pair. When you&#39;ve done that, you should add the keys to the <code>TRUSTED_PEERS</code> array in the same configuration file.</p><p>Let&#39;s consider an example of a minimum viable BFT network. In this network you have four peers, so that means that you need to create <em>four</em> different peer configuration files (<code>config.json</code>).</p><p>Each peer should have its own <code>PUBLIC_KEY</code> and <code>PRIVATE_KEY</code>. You should add all four public keys to the <code>TRUSTED_PEERS</code> array, including the peer that you&#39;re configuring. The same <code>TRUSTED_PEERS</code> array must be copied across all four configuration files.</p><p>Next, you must make sure that the peers agree on the <code>GENESIS_ACCOUNT</code> key pairs.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Don&#39;t worry about the fact that the private key for the genesis account is known to all peers. The genesis account loses all privileges after the first block gets committed.</p></div><h3 id="_3-register-a-non-genesis-account" tabindex="-1">3. Register a non-genesis account <a class="header-anchor" href="#_3-register-a-non-genesis-account" aria-hidden="true">#</a></h3><p>Finally, while the first client <em>could</em> use the genesis account to register new users, it&#39;s not a great idea for private networks. You should, instead, register a non-genesis account (for example <em>alice</em>@wonderland) and <code>unregister</code> the genesis account.</p><div class="warning custom-block"><p class="custom-block-title">NB</p><p><code>iroha_client_cli</code> currently doesn&#39;t support unregister instructions. If you plan on creating a private blockchain, you should consider writing your own client based on the <code>client</code> Rust crate, or any of the provided client libraries: <a href="https://github.com/hyperledger/iroha-python" target="_blank" rel="noopener noreferrer">iroha-python</a>, <a href="https://github.com/hyperledger/iroha-ios" target="_blank" rel="noopener noreferrer">iroha-iOS</a>, <a href="https://github.com/hyperledger/iroha-java" target="_blank" rel="noopener noreferrer">iroha-java</a>, or <a href="https://github.com/hyperledger/iroha-javascript/tree/iroha2" target="_blank" rel="noopener noreferrer">iroha-javascript</a>.</p></div><h2 id="keys-on-the-client-side" tabindex="-1">Keys on the Client Side <a class="header-anchor" href="#keys-on-the-client-side" aria-hidden="true">#</a></h2><p>Finally, let&#39;s talk about how keys are used in the client.</p><p>Every transaction is signed on behalf of some user, thus every operation requires a key. That doesn&#39;t mean that you need to explicitly provide a key every time.</p><p>For example, you need to have a user to register a user (just like you need scissors to cut off the tag from a pair of new scissors). But in order to register a user, you must also provide a new public key, so that the network can verify that it&#39;s that trustworthy <em>mad_hatter</em>@wonderland, and not some impostor (possibly sent by the <em>red_queen</em>), so there are cases where you need to provide a key explicitly.</p><p>Each time <code>iroha_client_cli</code> asks you to provide a <code>--key</code> argument, it&#39;s probably a good idea to generate a new key-pair.</p>`,25),n=[i];function s(c,h,p,l,d,u){return o(),t("div",null,n)}var f=e(r,[["render",s]]);export{g as __pageData,f as default};
